mapper.select:
select count(distinct cs.course_id)
from course_schedule cs
where cs.teacher_id = #{teacherId}
  and cs.semester_id = #{semesterId}

select count(distinct cl.id)
from course_schedule cs
join course_schedule_class csc on csc.schedule_id = cs.id
join class cl on csc.class_id = cl.id
where cs.teacher_id = #{teacherId}
  and cs.semester_id = #{semesterId}
